#!/usr/bin/env node
// git-advanced MCP stub. Maps methods to git subprocesses; refuses any
// argv that contains the substring 'commit' or '--force' (this server
// is read-only by design — write paths stay on `maddu git`).
import { spawn } from 'node:child_process';

function run(args) {
  return new Promise((resolve) => {
    const ch = spawn('git', args, { stdio: ['ignore', 'pipe', 'pipe'] });
    let out = '', err = '';
    ch.stdout.on('data', (b) => out += b.toString('utf8'));
    ch.stderr.on('data', (b) => err += b.toString('utf8'));
    ch.on('close', (code) => resolve({ code, out, err }));
  });
}

function safe(args) {
  for (const a of args) {
    if (a === 'commit' || a === 'push' || a === '--force' || a === '-f' || a === 'reset') return false;
  }
  return true;
}

process.stdin.setEncoding('utf8');
let buf = '';
process.stdin.on('data', async (chunk) => {
  buf += chunk;
  let idx;
  while ((idx = buf.indexOf('\n')) >= 0) {
    const line = buf.slice(0, idx);
    buf = buf.slice(idx + 1);
    if (!line.trim()) continue;
    let msg;
    try { msg = JSON.parse(line); } catch { continue; }
    if (msg.method === 'initialize') {
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, result: { protocolVersion: '0.1.0', capabilities: {}, serverInfo: { name: 'git-advanced', version: '0.1.0' } } }) + '\n');
      continue;
    }
    const args = Array.isArray(msg?.params?.argv) ? msg.params.argv : [];
    if (!safe(args)) {
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, error: { code: -32602, message: 'write operations refused — use maddu git' } }) + '\n');
      continue;
    }
    const res = await run(args);
    process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, result: { exitCode: res.code, stdout: res.out, stderr: res.err } }) + '\n');
  }
});
